	// receives memberArr and restricted group
	// returnes a memberArr restricted to people in the restricted group
	limitUsersToRestrictedGroup: function(userArr, restricted_group) {
		if (restricted_group == null  || restricted_group == '') {
			/// this should be checked before entering, but if not, just send same array back out
			return userArr;
		}else {

			var UserPermissions  = new UserInfoScripts();
			// STRY0095102 - get the nest list of groups
			// NOTE: may want to look at loading this one time for performance.  
			// If loading, build an object with top group as the key 
			// and the list of all groups under the top group as a comman delimitted string.
			var restricted_group_s = UserPermissions.getRestrictedGroupsAndDescendents(restricted_group);
			var restrictedMemArr = [];
			for (i=0; i<userArr.length; i++) {
				if  (UserPermissions.checkMemberinInGroup(userArr[i],restricted_group_s)) {
					restrictedMemArr.push(userArr[i]);
				}
			}
			return restrictedMemArr;
		}

	},

	type: 'taskerDynamicFilters'
});
